    fn tmp_path(name: &str) -> PathBuf {
        std::env::temp_dir().join(name)
    }

    fn cleanup(path: &PathBuf) {
        let _ = std::fs::remove_file(path);
    }

    fn setup(path: &PathBuf) -> StorageManager<RegularPageStore> {
        let store = RegularPageStore::create(path).unwrap();
        StorageManager::from_page_store(store).unwrap()
    }

    fn insert_nodes(manager: &mut StorageManager<RegularPageStore>, count: usize) -> Vec<u64> {
        let mut node_store = GraphNodeStore::new(manager);
        (0..count).map(|_| node_store.insert_node(1, 0, 0).unwrap()).collect()
    }

    // Test 1 — basic insert and get round trip
    #[test]
    fn test_insert_and_get_edge() {
        let path = tmp_path("test_edge_insert_get.nxra");
        cleanup(&path);
        let mut manager = setup(&path);

        let nodes = insert_nodes(&mut manager, 2);
        let mut edge_store = GraphEdgeStore::new(&mut manager);

        let edge_id = edge_store.insert_edge(nodes[0], nodes[1], 1, 1.0).unwrap();
        let record = edge_store.get_edge(edge_id).unwrap();

        assert_eq!(record.edge_id(), edge_id);
        assert_eq!(record.src_node_id(), nodes[0]);
        assert_eq!(record.dst_node_id(), nodes[1]);
        assert_eq!(record.weight(), 1.0);

        cleanup(&path);
    }

