    // Test 6 — outgoing cursor visits all inserted edges from a node
    #[test]
    fn test_outgoing_edges() {
        let path = tmp_path("test_edge_outgoing.nxra");
        cleanup(&path);
        let mut manager = setup(&path);

        let nodes = insert_nodes(&mut manager, 3);
        let mut edge_store = GraphEdgeStore::new(&mut manager);

        let e1 = edge_store.insert_edge(nodes[0], nodes[1], 1, 1.0).unwrap();
        let e2 = edge_store.insert_edge(nodes[0], nodes[2], 1, 2.0).unwrap();

        let mut cursor = edge_store.outgoing_cursor(nodes[0]).unwrap();
        let mut ids = [0u64; 2];
        let mut count = 0;
        while let Some(edge) = edge_store.cursor_next_outgoing(&mut cursor).unwrap() {
            ids[count] = edge.edge_id();
            count += 1;
        }

        assert_eq!(count, 2);
        assert!(ids.contains(&e1));
        assert!(ids.contains(&e2));

        cleanup(&path);
    }

